arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_116a9126086d4f2b94187cb3455aceb8.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

@* ───── Step Indicator Bar ───── *@
<nav class="d-flex align-items-center mb-4 flex-wrap gap-2" aria-label="Application steps">
    @for (int i = 0; i < StepLabels.Length; i++)
    {
        var step = i;
        var isCurrent = step == _currentStep;
        var isCompleted = step < _currentStep && !_submitted;

        <button type="button"
                class="btn btn-sm @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary") d-flex align-items-center gap-1"
                disabled="@(!isCompleted && !isCurrent)"
                @onclick="() => GoToStep(step)">
            @if (isCompleted)
            {
                <span>&#10003;</span>
            }
            <span>@StepLabels[step]</span>
        </button>

        @if (step < StepLabels.Length - 1)
        {
            <span class="text-muted">&rarr;</span>
        }
    }
</nav>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

@* ───── Step 1: Personal Info ───── *@
@if (_currentStep == 0)
{
    <div class="card p-4">
        <h4>Personal Information</h4>
        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="_fullName" placeholder="Jane Doe" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="_email" placeholder="jane@example.com" />
        </div>
        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
        </div>
        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input class="form-control" @bind="_address" placeholder="123 Main St, City, State" />
        </div>
        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_loading">
                @if (_loading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Next
            </button>
        </div>
    </div>
}

@* ───── Step 2: Work History ───── *@
@if (_currentStep == 1)
{
    <div class="card p-4">
        <h4>Work History</h4>
        @for (int i = 0; i < _workEntries.Count; i++)
        {
            var idx = i;
            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Position @(idx + 1)</h6>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                    }
                </div>
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_workEntries[idx].Company" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_workEntries[idx].Title" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" @bind="_workEntries[idx].StartDate" />
                    </div>
                    <div class="col-md-4">
